assert _utf16_len(PLACEHOLDER) == 2, "Placeholder must be a surrogate-pair emoji (UTF-16 len 2)"

# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
#  TEMP STORAGE
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
