REQUIRED_CHANNELS = [
    {"id": "-1003801304384", "name": "☠ 𝙎𝙃𝘼𝘿𝙊𝙒 𝗕𝗢𝗧𝗦 🌑", "link": "https://t.me/shadowzonebots"},
]

def check_joined(uid: int) -> list:
    """যে চ্যানেলে join করেনি সেগুলো return করে।"""
    not_joined = []
    for ch in REQUIRED_CHANNELS:
        try:
            member = bot.get_chat_member(ch["id"], uid)
            if member.status in ("left", "kicked", "banned"):
                not_joined.append(ch)
        except Exception:
            not_joined.append(ch)
    return not_joined

def send_join_notice(chat_id: int, not_joined: list):
    """Join করতে বলার message পাঠায়।"""
    markup = types.InlineKeyboardMarkup()
    for ch in not_joined:
        markup.add(types.InlineKeyboardButton(f"➕ {ch['name']}", url=ch["link"]))
    markup.add(types.InlineKeyboardButton("✅ 𝗩𝗘𝗥𝗜𝗙𝗬 𝗝𝗢𝗜𝗡", callback_data="check_join"))

    text = (
        f"{P}╔═══════◆◇◆═══════╗{P}\n"
        f"{P}      🔐 𝗝𝗢𝗜𝗡 𝗥𝗘𝗤𝗨𝗜𝗥𝗘𝗗      {P}\n"
        f"{P}╚═══════◆◇◆═══════╝{P}\n\n"
        f"{P} 𝗧𝗼 𝘂𝗻𝗹𝗼𝗰𝗸 𝘁𝗵𝗶𝘀 𝗽𝗿𝗲𝗺𝗶𝘂𝗺 𝗯𝗼𝘁,\n"
        "please join all channels below.\n\n"
    )
    for i, ch in enumerate(not_joined, 1):
        text += f"{P} {i}. {ch['name']}\n"
    text += (
        f"\n{P} After joining, tap Verify Join below.\n"
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}"
    )
    entities = _build_pe_entities(text, use_main=False)
    bot.send_message(chat_id, text, entities=entities or None, reply_markup=markup)


