@bot.message_handler(func=lambda m: m.text == "📣 𝗕𝗥𝗢𝗔𝗗𝗖𝗔𝗦𝗧" and m.from_user.id == ADMIN_ID)
def broadcast_start(message):
    sent = _send_pe_return(
        message.chat.id,
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}\n"
        f"{P}           BROADCAST          {P}\n"
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}\n\n"
        f"{P} Send your broadcast message now.\n"
        "It will be delivered to ALL users!\n\n"
        f"{P} Supports: Text, Photo, Video,\n"
        "Document, Sticker, Animation\n\n"
        f"{P} To cancel: /cancel\n"
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}",
        use_main=False
    )
    bot.register_next_step_handler(sent, do_broadcast)


def do_broadcast(message):
    if message.text and message.text.strip() == "/cancel":
        _send_pe(message.chat.id, f"{P} Broadcast cancelled.", reply_markup=admin_menu())
        return

    success = 0
    failed  = 0
    total   = len(all_users)
    status_msg = bot.send_message(message.chat.id, f"📢 Broadcasting to {total} users...")

    for uid in list(all_users):
        try:
            bot.copy_message(uid, message.chat.id, message.message_id)
            success += 1
            time.sleep(0.05)
        except Exception:
            failed += 1

    try:
        bot.delete_message(message.chat.id, status_msg.message_id)
    except Exception:
        pass

    _send_pe(
        message.chat.id,
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}\n"
        f"{P}      BROADCAST COMPLETE      {P}\n"
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}\n\n"
        f"{P} Total    : {total} users\n"
        f"{P} Success  : {success} ✅\n"
        f"{P} Failed   : {failed} ❌\n\n"
        f"{P}━━━━━━━━━━━━━━━━━━━━{P}",
        use_main=False, reply_markup=admin_menu()
    )


@bot.message_handler(commands=["broadcast"])
def broadcast_cmd(message):
    if message.from_user.id != ADMIN_ID:
        return
    if not message.reply_to_message:
        _send_pe(message.chat.id, f"{P} Reply to any message with /broadcast")
        return
    success = 0; failed = 0; total = len(all_users)
    for uid in list(all_users):
        try:
            bot.copy_message(uid, message.chat.id, message.reply_to_message.message_id)
            success += 1
            time.sleep(0.05)
        except Exception:
            failed += 1
    _send_pe(
        message.chat.id,
        f"{P} Broadcast done!\n{P} Success: {success}/{total}\n{P} Failed: {failed}",
        use_main=False
    )


