#  FALLBACK
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
@bot.message_handler(func=lambda m: True)
def fallback(message):
    uid = message.from_user.id
    if uid != ADMIN_ID:
        not_joined = check_joined(uid)
        if not_joined:
            send_join_notice(message.chat.id, not_joined)
            return
    register_user(uid)
    if not bot_active and uid != ADMIN_ID:
        bot_offline_notice(message)
        return
    kb = admin_menu() if uid == ADMIN_ID else main_menu()
    _send_pe(
        message.chat.id,
        f"{P} ✨ Please choose one option from the menu.\n\n"
        f"{P} MAKE POST — Create your post\n"
        f"{P} HELP      — Usage guide\n"
        f"{P} ABOUT BOT — Bot information",
        use_main=False, reply_markup=kb
    )


